function ProductsDetails() {
  useEffect(() => {
    Aos.init({ duration: 2000 });
    window.scrollTo(0, 0);
  }, []);

  const { ProductId } = useParams();

  const { data, isLoading, isSuccess, error } = useQuery({
    queryKey: ["details", ProductId],
    queryFn: () =>
      fetch(`http://127.0.0.1:8000/api/ProductDetails/${ProductId}`).then((res) =>
        res.json()
      ),
  });

  if (isLoading) return <Loading />;
  if (error) return <div>Error loading product details.</div>;

  return (
    <>
      {isSuccess && (
        <div className="hugy-body">
          <div className="border-container" data-aos="fade-left" data-aos-duration="1000">
            <h1 data-aos="fade-up" data-aos-duration="2700" className="gg">
              {data.title}
            </h1>

            <Swiper
              className="pd-swiper"
              effect={"coverflow"}
              grabCursor={true}
              centeredSlides={true}
              slidesPerView={"auto"}
              coverflowEffect={{
                rotate: 50,
                stretch: 0,
                depth: 100,
                modifier: 1,
                slideShadows: false,
              }}
              navigation={true}
              autoplay={{ delay: 3000 }}
              rewind={true}
              spaceBetween={10}
              pagination={{ clickable: true, type: "bullets" }}
              modules={[EffectCoverflow, Pagination, Navigation, Autoplay]}
            >
              {data.product_images &&
                parseNestedJson(data.product_images).images.slice(1).map((image, index) => (
                  <SwiperSlide key={index} className="pd-swiper-slide">
                    <img src={image} alt={`Slide ${index + 1}`} />
                  </SwiperSlide>
                ))}
            </Swiper>

            <div className="background-hugy">
              <section className="products-details-section">
                <p className="products-details-text-title">Product Description</p>
                <p className="products-details-text-info">
                  {data.description || "No description available"}
                </p>
                <p className="products-details-text-title">Product Ingredients</p>
                <p className="products-details-text-info">
                  {data.ingredients || "No ingredients listed"}
                </p>
                <p className="products-details-text-title">Weight</p>
                <p className="products-details-text-info">
                  {data.weight || "No weight specified"}
                </p>
                <p className="products-details-text-title">Packing</p>
                <p className="products-details-text-info">
                  {data.packing || "No packing information"}
                </p>
              </section>
            </div>
          </div>
        </div>
      )}
    </>
  );
}

export default ProductsDetails;
